mapper.select:
SELECT * FROM ( SELECT ROWNUM AS RNUM, A.* FROM ( SELECT * FROM HierarchicalBoard WHERE 1=1
START WITH BoardUpperNo = 0 CONNECT BY PRIOR BoardNo = BoardUpperNo ORDER SIBLINGS BY BoardGroupNo DESC ) A
) WHERE RNUM BETWEEN ${rowStart} AND ${rowEnd}

SELECT BoardNo, BoardTitle, BoardContent, UserId, BoardIndent
FROM HierarchicalBoard 
WHERE BoardNo=#{BoardNo}

mapper.update:
UPDATE HierarchicalBoard
SET BoardTitle=#{BoardTitle}, BoardContent=#{BoardContent}
WHERE BoardNo=#{BoardNo}
